const BaseModel = require('./BaseModel');
const pool = require('../config/database');

class Order extends BaseModel {
  constructor() {
    super('orders', [
      'user_id', 'status', 'total_amount',
      'shipping_address', 'notes'
    ]);
  }

  async findByUser(userId, limit = 50, offset = 0) {
    return this.findAll({
      where: { user_id: userId },
      limit,
      offset,
      orderBy: 'created_at',
      orderDir: 'DESC'
    });
  }

  async createOrderWithItems(orderData, items) {
    return this.transaction(async (client) => {
      // Create the order
      const orderResult = await client.query(
        `INSERT INTO "orders" ("user_id", "status", "total_amount", "shipping_address", "notes")
         VALUES ($1, $2, $3, $4, $5)
         RETURNING *`,
        [orderData.user_id, 'pending', orderData.total_amount,
         orderData.shipping_address, orderData.notes]
      );
      const order = orderResult.rows[0];

      // Insert order items and update stock
      const orderItems = [];
      for (const item of items) {
        // Decrease stock
        const stockResult = await client.query(
          `UPDATE "products"
           SET "stock_quantity" = "stock_quantity" - $1, "updated_at" = NOW()
           WHERE "id" = $2 AND "stock_quantity" >= $1
           RETURNING *`,
          [item.quantity, item.product_id]
        );

        if (stockResult.rows.length === 0) {
          throw new Error(`Insufficient stock for product ${item.product_id}`);
        }

        const itemResult = await client.query(
          `INSERT INTO "order_items" ("order_id", "product_id", "quantity", "unit_price")
           VALUES ($1, $2, $3, $4)
           RETURNING *`,
          [order.id, item.product_id, item.quantity, item.unit_price]
        );
        orderItems.push(itemResult.rows[0]);
      }

      return { order, items: orderItems };
    });
  }

  async updateStatus(orderId, status) {
    const validStatuses = ['pending', 'confirmed', 'shipped', 'delivered', 'cancelled'];
    if (!validStatuses.includes(status)) {
      throw new Error(`Invalid status: ${status}. Must be one of: ${validStatuses.join(', ')}`);
    }
    return this.update(orderId, { status });
  }
}

module.exports = new Order();


